sql:
SELECT discipline_name
FROM disciplines
WHERE subdiscipline = 'Computer Science';

SELECT reviewer_name, expertise
FROM grant_reviewers
WHERE experience > 5;

SELECT COUNT(*) AS total_reviews
FROM grant_reviews
WHERE reviewer_id = 1;

SELECT AVG(CAST(review_score AS REAL)) AS average_review_score
FROM grant_reviews
WHERE CAST(review_score AS REAL) > 70;

